input.command:
cat << 'EOF' > /tmp/setup.sh
#!/bin/bash
set -e

RUN_ID=$ZEALT_RUN_ID

# Create Source
SOURCE_JSON=$(hookdeck gateway source create --name "src-$RUN_ID" --type WEBHOOK --output json)
SOURCE_ID=$(echo $SOURCE_JSON | jq -r '.id')
echo "Created Source: $SOURCE_ID"

# Destination already created above, but we'll recreate or just use it. Let's recreate to be safe, or just use the ID we have. Wait, we can just create it again if it allows duplicates, or we can use a slightly different name?
# Actually, let's just delete the one we created or ignore it.
DEST_JSON=$(hookdeck gateway destination create --name "dst-$RUN_ID" --type MOCK_API --output json)
DEST_ID=$(echo $DEST_JSON | jq -r '.id')
echo "Created Destination: $DEST_ID"

# Create Transformation
cat << 'INNER_EOF' > /tmp/transform.js
addHandler("transform", (request, context) => {
  const body = request.body;
  if (!body || typeof body !== "object") {
    console.log("validation_failed: user_id");
    return null;
  }

  if (typeof body.user_id !== "string" || body.user_id === "") {
    console.log("validation_failed: user_id");
    return null;
  }

  if (typeof body.amount !== "number" || !Number.isFinite(body.amount)) {
    console.log("validation_failed: amount");
    return null;
  }

  return request;
});
INNER_EOF

TRANSFORM_JSON=$(hookdeck gateway transformation create --name "validate-$RUN_ID" --code-file /tmp/transform.js --output json)
TRANSFORM_ID=$(echo $TRANSFORM_JSON | jq -r '.id')
echo "Created Transformation: $TRANSFORM_ID"

# Create Connection
CONN_JSON=$(hookdeck gateway connection create --name "conn-$RUN_ID" --source-id "$SOURCE_ID" --destination-id "$DEST_ID" --rule-transform-name "$TRANSFORM_ID" --output json)
CONN_ID=$(echo $CONN_JSON | jq -r '.id')
echo "Created Connection: $CONN_ID"

# Write to log file
mkdir -p /home/user/hookdeck-task
cat << INNER_EOF > /home/user/hookdeck-task/output.log
Source ID: $SOURCE_ID
Transformation ID: $TRANSFORM_ID
INNER_EOF

echo "Done"
EOF
chmod +x /tmp/setup.sh
/tmp/setup.sh
